VALUES
  ('diplomatic-d3cf880d-moex-00024', 'diplomatic-d3cf880d', 'diplomatic-d3cf880d-moex-114-10317cea', 'sub-diplomatic-d3cf880d-02', NULL, 'single_choice', '下列何者並非一國法院經常用以決定跨境電信詐騙犯罪案件管轄權之依據？', '["領域管轄", "普遍管轄", "行為人國籍管轄", "被害者國籍管轄"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:24:44+00:00", "source_pdf_sha1": "50baf7169a04", "answer_pdf_sha1": "f8981815935e", "source_family": "moex-gov-tw", "moex": {"exam_code": "114140", "c": "104", "s": "0701", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "國際公法", "year": "114", "exam_name": "114年公務人員特種考試外交領事人員及外交行政人員考試、國際經濟商務人員考試、民航人員考試、原住民族考試", "original_question_number": 11, "answer_corrected": false, "flags": [], "civil_slug": "diplomatic", "civil_category": "外交領事人員-葡萄牙文組"}'::jsonb, NULL),
  ('diplomatic-d3cf880d-moex-00025', 'diplomatic-d3cf880d', 'diplomatic-d3cf880d-moex-114-10317cea', 'sub-diplomatic-d3cf880d-02', NULL, 'single_choice', '依2001年《國家對國際不法行為的責任條款草案》，關於「一國國際不法行為之要素」，下列敘述 何者錯誤？', '["是由一個不法的作為或不作為造成", "存在一個違反義務的作為或不作為", "不法的作為或不作為是可歸責於某一個國家", "國際不法行為之認定應依國際法及國內法共同為之"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:24:44+00:00", "source_pdf_sha1": "50baf7169a04", "answer_pdf_sha1": "f8981815935e", "source_family": "moex-gov-tw", "moex": {"exam_code": "114140", "c": "104", "s": "0701", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "國際公法", "year": "114", "exam_name": "114年公務人員特種考試外交領事人員及外交行政人員考試、國際經濟商務人員考試、民航人員考試、原住民族考試", "original_question_number": 12, "answer_corrected": false, "flags": [], "civil_slug": "diplomatic", "civil_category": "外交領事人員-葡萄牙文組"}'::jsonb, NULL),
  ('diplomatic-d3cf880d-moex-00026', 'diplomatic-d3cf880d', 'diplomatic-d3cf880d-moex-114-10317cea', 'sub-diplomatic-d3cf880d-02', NULL, 'single_choice', '隨著國際環境法法律原則之發展，下列敘述何者錯誤？', '["國家負有一般義務確保其管轄範圍內之活動尊重他國環境，已為 1996 年國際法院「威脅使用 或使用核武器合法性」諮詢意見所確認", "污染者付費原則已被1972年《聯合國人類環境會議宣言》確認為一般法律原則", "要求進行環境影響評估已為2010年國際法院「烏拉圭河紙漿廠」判決所確認", "永續發展概念已被運用於一般經貿協定中"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:24:44+00:00", "source_pdf_sha1": "50baf7169a04", "answer_pdf_sha1": "f8981815935e", "source_family": "moex-gov-tw", "moex": {"exam_code": "114140", "c": "104", "s": "0701", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "國際公法", "year": "114", "exam_name": "114年公務人員特種考試外交領事人員及外交行政人員考試、國際經濟商務人員考試、民航人員考試、原住民族考試", "original_question_number": 13, "answer_corrected": false, "flags": [], "civil_slug": "diplomatic", "civil_category": "外交領事人員-葡萄牙文組"}'::jsonb, NULL),
  ('diplomatic-d3cf880d-moex-00027', 'diplomatic-d3cf880d', 'diplomatic-d3cf880d-moex-114-10317cea', 'sub-diplomatic-d3cf880d-02', NULL, 'single_choice', '依據《聯合國憲章》第7章，有關聯合國安全理事會，下列敘述何者錯誤？', '["在「人道干預」之情形下，不需事前經安全理事會之決議，聯合國秘書長得逕自要求會員國採 取緊急軍事措施", "安全理事會應斷定任何和平之威脅、和平之破壞、或侵略行為之是否存在，並應作成建議或採 取適當之辦法，以維持或恢復國際和平及安全", "安全理事會得採取必要之空海陸軍行動，以維持或恢復國際和平及安全", "安全理事會得決定採取武力以外之辦法，以維持國際和平與安全，並得要求聯合國會員採取該 相關措施"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:24:44+00:00", "source_pdf_sha1": "50baf7169a04", "answer_pdf_sha1": "f8981815935e", "source_family": "moex-gov-tw", "moex": {"exam_code": "114140", "c": "104", "s": "0701", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "國際公法", "year": "114", "exam_name": "114年公務人員特種考試外交領事人員及外交行政人員考試、國際經濟商務人員考試、民航人員考試、原住民族考試", "original_question_number": 14, "answer_corrected": false, "flags": [], "civil_slug": "diplomatic", "civil_category": "外交領事人員-葡萄牙文組"}'::jsonb, NULL),
  ('diplomatic-d3cf880d-moex-00028', 'diplomatic-d3cf880d', 'diplomatic-d3cf880d-moex-114-10317cea', 'sub-diplomatic-d3cf880d-02', NULL, 'single_choice', '依《聯合國憲章》第4條，關於申請成為聯合國會員國的程序，下列敘述何者正確？', '["經大會會員國二分之一之出席與同意行之", "經安全理事會理事國三分之二之出席與同意", "由大會經安全理事會之推薦以決議行之", "經安全理事會理事國二分之一之出席與同意"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:24:44+00:00", "source_pdf_sha1": "50baf7169a04", "answer_pdf_sha1": "f8981815935e", "source_family": "moex-gov-tw", "moex": {"exam_code": "114140", "c": "104", "s": "0701", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "國際公法", "year": "114", "exam_name": "114年公務人員特種考試外交領事人員及外交行政人員考試、國際經濟商務人員考試、民航人員考試、原住民族考試", "original_question_number": 15, "answer_corrected": false, "flags": [], "civil_slug": "diplomatic", "civil_category": "外交領事人員-葡萄牙文組"}'::jsonb, NULL),
  ('diplomatic-d3cf880d-moex-00029', 'diplomatic-d3cf880d', 'diplomatic-d3cf880d-moex-114-10317cea', 'sub-diplomatic-d3cf880d-02', NULL, 'single_choice', '世界貿易組織之規範體系不包括下列何協定？', '["與貿易有關之貨幣互換協定", "服務貿易總協定", "與貿易有關之智慧財產權協定", "技術性貿易障礙協定"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:24:44+00:00", "source_pdf_sha1": "50baf7169a04", "answer_pdf_sha1": "f8981815935e", "source_family": "moex-gov-tw", "moex": {"exam_code": "114140", "c": "104", "s": "0701", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "國際公法", "year": "114", "exam_name": "114年公務人員特種考試外交領事人員及外交行政人員考試、國際經濟商務人員考試、民航人員考試、原住民族考試", "original_question_number": 16, "answer_corrected": false, "flags": [], "civil_slug": "diplomatic", "civil_category": "外交領事人員-葡萄牙文組"}'::jsonb, NULL),
  ('diplomatic-d3cf880d-moex-00030', 'diplomatic-d3cf880d', 'diplomatic-d3cf880d-moex-114-10317cea', 'sub-diplomatic-d3cf880d-02', NULL, 'single_choice', '菲律賓於2013年1月提出有關南海爭議的爭端解決，是向下列何者提出？', '["常設仲裁法院", "國際法院", "國際海洋法法庭", "《聯合國海洋法公約》附件七仲裁庭"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:24:44+00:00", "source_pdf_sha1": "50baf7169a04", "answer_pdf_sha1": "f8981815935e", "source_family": "moex-gov-tw", "moex": {"exam_code": "114140", "c": "104", "s": "0701", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "國際公法", "year": "114", "exam_name": "114年公務人員特種考試外交領事人員及外交行政人員考試、國際經濟商務人員考試、民航人員考試、原住民族考試", "original_question_number": 17, "answer_corrected": false, "flags": [], "civil_slug": "diplomatic", "civil_category": "外交領事人員-葡萄牙文組"}'::jsonb, NULL),
  ('diplomatic-d3cf880d-moex-00031', 'diplomatic-d3cf880d', 'diplomatic-d3cf880d-moex-114-10317cea', 'sub-diplomatic-d3cf880d-02', NULL, 'single_choice', '《聯合國憲章》第2條規定多項原則，下列敘述何者錯誤？', '["各會員國應以和平方法解決其國際爭端，俾免危及國際和平、安全及正義", "各會員國在其國際關係上不得使用威脅或武力，或以與聯合國宗旨不符之任何其他方法，侵害 任何會員國或國家之領土完整或政治獨立", "當任何會員遭受軍事攻擊時，聯合國大會得採取必要之空海陸軍行動，以維持或恢復該國之和 平及安全", "本憲章不得認為授權聯合國干涉在本質上屬於任何國家國內管轄之事件，且並不要求會員國將 該項事件依本憲章提請解決；但此項原則不妨礙第7章內執行辦法之適用"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:24:44+00:00", "source_pdf_sha1": "50baf7169a04", "answer_pdf_sha1": "f8981815935e", "source_family": "moex-gov-tw", "moex": {"exam_code": "114140", "c": "104", "s": "0701", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "國際公法", "year": "114", "exam_name": "114年公務人員特種考試外交領事人員及外交行政人員考試、國際經濟商務人員考試、民航人員考試、原住民族考試", "original_question_number": 18, "answer_corrected": false, "flags": [], "civil_slug": "diplomatic", "civil_category": "外交領事人員-葡萄牙文組"}'::jsonb, NULL),
  ('diplomatic-d3cf880d-moex-00032', 'diplomatic-d3cf880d', 'diplomatic-d3cf880d-moex-114-10317cea', 'sub-diplomatic-d3cf880d-02', NULL, 'single_choice', '1949年四個日内瓦公約的共同第3條，確立在非國際性武裝衝突的情形下，衝突之各方對不實際 參與戰鬥人員應給予之人道待遇。下列何者非共同第3條具體提及之內容？', '["禁止劫持作為人質", "禁止強迫遷移", "禁止未經公正審判而判處刑罰", "公正的人道團體得向衝突各方提供服務的權利"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:24:44+00:00", "source_pdf_sha1": "50baf7169a04", "answer_pdf_sha1": "f8981815935e", "source_family": "moex-gov-tw", "moex": {"exam_code": "114140", "c": "104", "s": "0701", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "國際公法", "year": "114", "exam_name": "114年公務人員特種考試外交領事人員及外交行政人員考試、國際經濟商務人員考試、民航人員考試、原住民族考試", "original_question_number": 19, "answer_corrected": false, "flags": [], "civil_slug": "diplomatic", "civil_category": "外交領事人員-葡萄牙文組"}'::jsonb, NULL),
  ('diplomatic-d3cf880d-moex-00033', 'diplomatic-d3cf880d', 'diplomatic-d3cf880d-moex-114-10317cea', 'sub-diplomatic-d3cf880d-02', NULL, 'single_choice', '關於與國際環境保護相關的公約規範，下列敘述何者錯誤？', '["《控制危險廢物越境轉移及其處置巴塞爾公約》（BaselConventionontheControlofTransboundary MovementsofHazardousWastesandTheirDisposal）完全禁止廢棄物跨國移轉", "《防止海洋油污染國際公約》（InternationalConventionforthePreventionofPollutionoftheSeaby Oil）限制有害物質的排放", "依據《生物多樣性公約》（ConventiononBiologicalDiversity），可否取得遺傳資源的決定權屬於 國家政府", "《巴黎協定》採國家自主貢獻方式，減量降低溫室氣體的排放"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:24:44+00:00", "source_pdf_sha1": "50baf7169a04", "answer_pdf_sha1": "f8981815935e", "source_family": "moex-gov-tw", "moex": {"exam_code": "114140", "c": "104", "s": "0701", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "國際公法", "year": "114", "exam_name": "114年公務人員特種考試外交領事人員及外交行政人員考試、國際經濟商務人員考試、民航人員考試、原住民族考試", "original_question_number": 20, "answer_corrected": false, "flags": [], "civil_slug": "diplomatic", "civil_category": "外交領事人員-葡萄牙文組"}'::jsonb, NULL)
